mapper.select:
SELECT nnum, ntitle, nwriter, NCONTENT, nhit, ndate row_num FROM (SELECT nnum, ntitle, nwriter, NCONTENT, nhit, ndate, ROW_NUMBER() OVER(ORDER BY num desc) AS row_num FROM notice
writer like '%' || #{searchValue} || '%'
title like '%' || #{searchValue} || '%'
content like '%' || #{searchValue} || '%'
) numbered_rows WHERE row_num BETWEEN #{begin} AND #{end}
